module RefModule(clk, rst, up, down, q);

    input clk;
    input rst;
    input up;
    input down;
    output [3:0] q;
    reg [3:0] q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
    begin
        if (rst)
            q <= 4'b0000;
        else if (up && !down)
            q <= q + 1;
        else if (down && !up)
            q <= q - 1;
    end

endmodule
